import sys

def solve(data: str) -> str:
    score = int(data.strip())
    if not 0 <= score <= 100:
        return "invalid"
    if score < 50:
        return "fail"
    if score < 80:
        return "pass"
    return "distinction"

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
